body.script:
const coordsData = document.getElementById('coordsData');
let isFrozen = false; // 장면 연출 모드일 때 마우스 추적 정지

// 1. 마우스 및 터치 트래킹
function updateCoordinates(clientX, clientY) {
    if(isFrozen) return;

    document.documentElement.style.setProperty('--mouse-x', clientX + 'px');
    document.documentElement.style.setProperty('--mouse-y', clientY + 'px');

    const x = String(clientX).padStart(4, '0');
    const y = String(clientY).padStart(4, '0');
    const hex = Math.floor(Math.random()*0xFFF).toString(16).toUpperCase().padStart(3, '0');
    coordsData.innerHTML = `SCANNING...<br>POS: X_${x} Y_${y}<br>VAL: 0x${hex}`;
}

document.addEventListener('mousemove', (e) => updateCoordinates(e.clientX, e.clientY));
document.addEventListener('touchmove', (e) => updateCoordinates(e.touches.clientX, e.touches.clientY));

// 2. 캡처용 장면 연출 기능 (Director Mode)
function setScene(sceneType) {
    isFrozen = true;
    document.getElementById('directorMenu').classList.add('active'); // 메뉴 숨김 방지

    if (sceneType === 1) {
        // 장면 1: 렌즈를 완전히 없애서 인간 시각의 압도적인 타이포그래피만 캡처
        document.documentElement.style.setProperty('--lens-size', '0vw');
        coordsData.innerHTML = `TARGET_LOST`;
    } else if (sceneType === 2) {
        // 장면 2: 정중앙에 커다란 렌즈를 띄워 기계의 완벽한 해독 뷰를 캡처
        document.documentElement.style.setProperty('--mouse-x', '50vw');
        document.documentElement.style.setProperty('--mouse-y', '50vh');
        document.documentElement.style.setProperty('--lens-size', '25vw');
        coordsData.innerHTML = `LOCKED_ON_TARGET<br>POS: X_CENTER Y_CENTER<br>VAL: 0xSYS`;
    }
}

// 3. 다시 마우스 반응형으로 복귀
function resumeInteraction() {
    isFrozen = false;
    document.documentElement.style.setProperty('--lens-size', '18vw');
    document.getElementById('directorMenu').classList.remove('active');
}

// 4. 단일 HTML 파일로 다운로드
function downloadHTML() {
    // 현재 화면의 HTML을 복사
    const clone = document.documentElement.cloneNode(true);

    // 제출용 파일에는 우측 하단의 이 UI 메뉴가 보이지 않도록 깔끔하게 삭제 처리!
    const menu = clone.querySelector('#directorMenu');
    if(menu) menu.remove();

    const htmlContent = "<!DOCTYPE html>\n" + clone.outerHTML;
    const blob = new Blob([htmlContent], {type: "text/html"});
    const url = URL.createObjectURL(blob);

    const a = document.createElement('a');
    a.href = url;
    a.download = "Slanted_Seoul_Submission.html";
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
}

// 5. 이미지 (PNG/SVG) 다운로드 기능 추가
function downloadImage(type) {
    const menu = document.getElementById('directorMenu');
    menu.style.display = 'none'; // 캡처 시 메뉴 숨김

    // 렌즈 애니메이션이 멈출 시간을 약간 줌
    setTimeout(() => {
        const options = { 
            quality: 1.0, 
            pixelRatio: 2, // 2배수 고해상도 출력
            style: { cursor: 'default' } 
        };

        const exportFunc = type === 'png' 
            ? htmlToImage.toPng(document.body, options) 
            : htmlToImage.toSvg(document.body, options);

        exportFunc.then(function (dataUrl) {
            const link = document.createElement('a');
            link.download = `SAIOUL_Artwork.${type}`;
            link.href = dataUrl;
            link.click();
            menu.style.display = 'flex'; // 캡처 후 메뉴 다시 표시
        }).catch(function (error) {
            console.error('Export Error:', error);
            alert('이미지 생성 중 오류가 발생했습니다.');
            menu.style.display = 'flex';
        });
    }, 100);
}
